import BasicInput from "../../components/Input/BasicInput";

const AddFriend = () => {
  return (
    <div>
      <header>
        <h2>ADD FRIEND</h2>
        <form>
          <div>You can add friends with their username.</div>
          <BasicInput></BasicInput>
        </form>
      </header>
    </div>
  );
};

export default AddFriend;
